// Script Continued Below
function onChange(control, oldValue, newValue, isLoading, isTemplate) {
	if(g_form.getValue('parent') + '' != ''){
		// DFCT0010555
		g_form.setReadOnly("u_request_type", true);

		var currentSysId = g_form.getUniqueValue();
		var isNewRecord = g_form.isNewRecord();
		var isTaskOwner = g_user.userID == g_form.getValue('parent.u_task_requester');
		g_form.setReadOnly('parent.u_task_requester', true);

		if (isLoading) {
			var parentSuspenseDate = g_form.getValue('parent.suspense_date');
			var requestType = g_form.getValue('u_request_type');
			var status = g_form.getValue('u_status');

			g_form.setReadOnly('parent.primary_assignee', true);
			g_form.setReadOnly('parent.assigned_to', true);

			// remove the OU Request types
			g_form.removeOption('u_request_type','member_add');
			g_form.removeOption('u_request_type','member_remove');
			g_form.removeOption('u_request_type','member_update');
			g_form.removeOption('u_request_type','sub_ou_add');
			g_form.removeOption('u_request_type','sub_ou_remove');
			g_form.removeOption('u_request_type','ou_update');
			g_form.removeOption('u_request_type','ou_remove');

			if (isNewRecord == true){
				g_form.setDisplay('u_status', false);
			}

			if (isNewRecord != true){ 
				g_form.setReadOnly('u_request_comments', true);
				g_form.setReadOnly('u_response_comments', false);
			}

			if (status == "In progress"){

				switch(requestType) {
					case "Reassignment" :
						g_form.setDisplay('u_requested_suspense_date', false);
						g_form.setMandatory('u_requested_suspense_date', false);
						//STRY0077968 
						g_form.setDisplay('requested_suspense_date_approved', false);
						g_form.setMandatory('requested_suspense_date_approved', false);
						break;

					case "Extension" :
						g_form.setDisplay('u_requested_suspense_date', true);
						g_form.setReadOnly("u_requested_suspense_date", true);
						g_form.setMandatory('u_requested_suspense_date', true);

						//STRY0077968 
						g_form.setDisplay('requested_suspense_date_approved', true);
						// Read only unless task owner					
						g_form.setReadOnly("requested_suspense_date_approved", !isTaskOwner);
						g_form.setMandatory('requested_suspense_date_approved', isTaskOwner);
						// default the date to approve the the date requested
						if(isTaskOwner && g_form.getValue('requested_suspense_date_approved')+'' == '') 
							g_form.setValue('requested_suspense_date_approved', g_form.getValue('u_requested_suspense_date'));
						g_form.showFieldMsg('requested_suspense_date_approved','Update this field to Approve a different Suspense Date than the Requested Suspense Date','info'); 
						break;

					case "Clarification" :
						g_form.setDisplay('u_requested_suspense_date', false);
						g_form.setMandatory('u_requested_suspense_date', false);
						//STRY0077968 
						g_form.setDisplay('requested_suspense_date_approved', false);
						g_form.setMandatory('requested_suspense_date_approved', false);
						g_form.setMandatory("u_response_comments", true);
						break;		
				}
			}

			if (status == "Completed"){
				g_form.setReadOnly("u_requested_suspense_date", true);
				//STRY0077968 
				g_form.setReadOnly("requested_suspense_date_approved", true);
				g_form.setReadOnly("u_request_comments", true);
				g_form.setReadOnly("u_response_comments", true);

				if (requestType != 'Extension'){
					g_form.setDisplay('u_requested_suspense_date', false);
					//STRY0077968 
					g_form.setDisplay('requested_suspense_date_approved', false);
				}
			}

			return;
		}

		//onChange
		if(newValue != oldValue){ 

			var newRequestType = g_form.getValue('u_request_type');
			var newparentSuspenseDate = g_form.getValue('parent.suspense_date');

			switch(newRequestType) {
				case "Reassignment" :
					g_form.setDisplay('u_requested_suspense_date', false);
					g_form.setMandatory('u_requested_suspense_date', false);
					//STRY0077968 
					g_form.setDisplay('requested_suspense_date_approved', false);
					g_form.setMandatory('requested_suspense_date_approved', false);				
					break;

				case "Extension" :
					g_form.setDisplay('u_requested_suspense_date', true);
					g_form.setMandatory('u_requested_suspense_date', true);
					//STRY0077968 
					g_form.setDisplay('requested_suspense_date_approved', true);
					// Read only unless task owner					
					g_form.setReadOnly("requested_suspense_date_approved", !isTaskOwner);
					g_form.setMandatory('requested_suspense_date_approved', isTaskOwner);
					// default the date to approve the the date requested
					if(isTaskOwner && g_form.getValue('requested_suspense_date_approved')+'' == '') 
						g_form.setValue('requested_suspense_date_approved', g_form.getValue('u_requested_suspense_date'));
					g_form.showFieldMsg('requested_suspense_date_approved','Update this field to Approve a different Suspense Date than the Requested Suspense Date','info'); 
					break;

				case "Clarification" :
					g_form.setDisplay('u_requested_suspense_date', false);
					//STRY0077968 
					g_form.setDisplay('requested_suspense_date_approved', false);
					g_form.setMandatory('requested_suspense_date_approved', false);
					g_form.setMandatory('u_requested_suspense_date', false);
					g_form.setMandatory("u_response_comments", true);
					break;		
			}

		}

	}
}
